window.PACTO.acts["dir-2004-83"]={"label": "DIRETTIVA 2004/83/CE DEL CONSIGLIO", "short": "Dir. 83/2004", "file": "ext-dir-2004-83.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/dir/2004/83/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto e campo d'applicazione", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">La presente direttiva stabilisce norme minime sull'attribuzione, a cittadini di paesi terzi o apolidi, della qualifica di rifugiato o di persona altrimenti bisognosa di protezione internazionale, nonché norme minime sul contenuto della protezione riconosciuta.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Ai fini della presente direttiva, si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«protezione internazionale»: lo status di rifugiato e di protezione sussidiaria quale definito alle lettere d) e f);</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«convenzione di Ginevra»: la convenzione relativa allo status dei rifugiati, firmata a Ginevra il 28 luglio 1951, come modificata dal protocollo di New York del 31 gennaio 1967;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«rifugiato»: cittadino di un paese terzo il quale, per il timore fondato di essere perseguitato per motivi di razza, religione, nazionalità, opinione politica o appartenenza ad un determinato gruppo sociale, si trova fuori dal paese di cui ha la cittadinanza e non può o, a causa di tale timore, non vuole avvalersi della protezione di detto paese, oppure apolide che si trova fuori dal paese nel quale aveva precedentemente la dimora abituale per le stesse ragioni succitate e non può o, a causa di siffatto timore, non vuole farvi ritorno, e al quale non si applica l'articolo 12;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«status di rifugiato»: il riconoscimento, da parte di uno Stato membro, di un cittadino di un paese terzo o di un apolide quale rifugiato;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«persona ammissibile alla protezione sussidiaria»: cittadino di un paese terzo o apolide che non possiede i requisiti per essere riconosciuto come rifugiato ma nei cui confronti sussistono fondati motivi di ritenere che, se ritornasse nel paese di origine, o, nel caso di un apolide, se ritornasse nel paese nel quale aveva precedentemente la dimora abituale, correrebbe un rischio effettivo di subire un grave danno come definito all'articolo 15, e al quale non si applica l'articolo 17, paragrafi 1 e 2, e il quale non può o, a causa di tale rischio, non vuole avvalersi della protezione di detto paese;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«status di protezione sussidiaria»: il riconoscimento, da parte di uno Stato membro, di un cittadino di un paese terzo o di un apolide quale persona ammissibile alla protezione sussidiaria;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«domanda di protezione internazionale»: una richiesta di protezione rivolta ad uno Stato membro da parte di un cittadino di un paese terzo o di un apolide di cui si può ritenere che intende ottenere lo status di rifugiato o lo status di protezione sussidiaria e che non sollecita esplicitamente un diverso tipo di protezione, non contemplato nel campo d'applicazione della presente direttiva, che possa essere richiesto con domanda separata;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«familiari»: i seguenti soggetti appartenenti al nucleo familiare, già costituito nel paese di origine, del beneficiario dello status di rifugiato o dello status di protezione sussidiaria che si trovano nel medesimo Stato membro in connessione alla domanda di protezione internazionale:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il coniuge del beneficiario dello status di rifugiato o dello status di protezione sussidiaria, o il suo partner non sposato, avente con questi una relazione stabile, se la legislazione o la prassi dello Stato membro interessato equipara le coppie non sposate a quelle sposate nel quadro della legge sugli stranieri,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i figli minori della coppia di cui al primo trattino o del beneficiario dello status di rifugiato o dello status di protezione sussidiaria, a condizione che siano non sposati ed a suo carico, indipendentemente dal fatto che siano legittimi, naturali o adottivi secondo le definizioni del diritto nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«minore non accompagnato»: il cittadino di un paese terzo o l'apolide d'età inferiore ai diciotto anni che giunga nel territorio dello Stato membro senza essere accompagnato da un adulto che ne sia responsabile in base alla legge o agli usi, fino a quando non sia effettivamente affidato ad un tale adulto; il termine include i minori che vengono abbandonati dopo essere entrati nel territorio degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«permesso di soggiorno»: qualsiasi titolo o autorizzazione rilasciati dalle autorità di uno Stato membro nella forma prevista dalla legislazione nazionale, che permetta ad un cittadino di un paese terzo o ad un apolide di soggiornare nel territorio dello Stato membro stesso;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«paese di origine»: il paese o i paesi di cui il richiedente è cittadino o, per un apolide, in cui aveva precedentemente la dimora abituale.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Disposizioni più favorevoli", "anchor": "art_3", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri hanno facoltà di introdurre o mantenere in vigore disposizioni più favorevoli in ordine alla determinazione dei soggetti che possono essere considerati rifugiati o persone ammissibili alla protezione sussidiaria nonché in ordine alla definizione degli elementi sostanziali della protezione internazionale, purché siano compatibili con le disposizioni della presente direttiva.</p>"]]}, "4": {"label": "Articolo 4", "heading": "Esame dei fatti e delle circostanze", "anchor": "art_4", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono ritenere che il richiedente sia tenuto a produrre quanto prima tutti gli elementi necessari a motivare la domanda di protezione internazionale. Lo Stato membro è tenuto, in cooperazione con il richiedente, a esaminare tutti gli elementi significativi della domanda.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli elementi di cui al paragrafo 1 sono le dichiarazioni del richiedente e tutta la documentazione in possesso del richiedente in merito alla sua età, estrazione, anche, ove occorra, dei congiunti, identità, cittadinanza/e, paese/i e luogo/luoghi in cui ha soggiornato in precedenza, domande d'asilo pregresse, itinerari di viaggio, documenti di identità e di viaggio nonché i motivi della sua domanda di protezione internazionale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'esame della domanda di protezione internazionale deve essere effettuato su base individuale e prevede la valutazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">di tutti i fatti pertinenti che riguardano il paese d'origine al momento dell'adozione della decisione in merito alla domanda, comprese le disposizioni legislative e regolamentari del paese d'origine e relative modalità di applicazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">della dichiarazione e della documentazione pertinenti presentate dal richiedente che deve anche render noto se ha già subito o rischia di subire persecuzioni o danni gravi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">della situazione individuale e delle circostanze personali del richiedente, in particolare l'estrazione, il sesso e l'età, al fine di valutare se, in base alle circostanze personali del richiedente, gli atti a cui è stato o potrebbe essere esposto si configurino come persecuzione o danno grave;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dell'eventualità che le attività svolte dal richiedente dopo aver lasciato il paese d'origine abbiano mirato esclusivamente o principalmente a creare le condizioni necessarie alla presentazione di una domanda di protezione internazionale, al fine di stabilire se dette attività espongano il richiedente a persecuzione o a danno grave in caso di rientro nel paese;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dell'eventualità che ci si possa ragionevolmente attendere dal richiedente un ricorso alla protezione di un altro paese di cui potrebbe dichiararsi cittadino.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il fatto che un richiedente abbia già subito persecuzioni o danni gravi o minacce dirette di siffatte persecuzioni o danni costituisce un serio indizio della fondatezza del timore del richiedente di subire persecuzioni o del rischio effettivo di subire danni gravi, a meno che vi siano buoni motivi per ritenere che tali persecuzioni o danni gravi non si ripeteranno.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Quando gli Stati membri applicano il principio in base al quale il richiedente è tenuto a motivare la sua domanda di protezione internazionale e qualora taluni aspetti delle dichiarazioni del richiedente non siano suffragati da prove documentali o di altro tipo, la loro conferma non è comunque necessaria se sono soddisfatte le seguenti condizioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha compiuto sinceri sforzi per circostanziare la domanda;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tutti gli elementi pertinenti in suo possesso sono stati prodotti ed è stata fornita una spiegazione soddisfacente dell'eventuale mancanza di altri elementi significativi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le dichiarazioni del richiedente sono ritenute coerenti e plausibili e non sono in contraddizione con le informazioni generali e specifiche pertinenti al suo caso di cui si dispone;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il richiedente ha presentato la domanda di protezione internazionale il prima possibile, a meno che egli non dimostri di aver avuto buoni motivi per ritardarla; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è accertato che il richiedente è in generale attendibile.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Bisogno di protezione internazionale sorto fuori dal paese d'origine («sur place»)", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il timore fondato di essere perseguitato o il rischio effettivo di subire un danno grave può essere basato su avvenimenti verificatisi dopo la partenza del richiedente dal suo paese di origine.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il timore fondato di essere perseguitato o il rischio effettivo rischio di subire un danno grave può essere basato su attività svolte dal richiedente dopo la sua partenza dal paese d'origine, in particolare quando sia accertato che le attività addotte costituiscono l'espressione e la continuazione di convinzioni od orientamenti già manifestati nel paese d'origine.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatta salva la convenzione di Ginevra, gli Stati membri possono stabilire di non riconoscere di norma lo status di rifugiato a un richiedente che abbia introdotto una domanda successiva se il rischio di persecuzioni è basato su circostanze determinate dal richiedente stesso dopo la partenza dal paese di origine.</p>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Responsabili della persecuzione o del danno grave", "anchor": "art_6", "frags": [[null, "<p class=\"oj-normal\">I responsabili della persecuzione o del danno grave possono essere:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo Stato;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i partiti o le organizzazioni che controllano lo Stato o una parte consistente del suo territorio;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">soggetti non statuali, se può essere dimostrato che i responsabili di cui alle lettere a) e b), comprese le organizzazioni internazionali, non possono o non vogliono fornire protezione contro persecuzioni o danni gravi come definito all'articolo 7.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "7": {"label": "Articolo 7", "heading": "Soggetti che offrono protezione", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La protezione può essere offerta:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dallo Stato; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dai partiti o organizzazioni, comprese le organizzazioni internazionali, che controllano lo Stato o una parte consistente del suo territorio.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La protezione è in generale fornita se i soggetti di cui al paragrafo 1 adottano adeguate misure per impedire che possano essere inflitti atti persecutori o danni gravi, avvalendosi tra l'altro di un sistema giuridico effettivo che permetta di individuare, di perseguire penalmente e di punire gli atti che costituiscono persecuzione o danno grave e se il richiedente ha accesso a tale protezione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Per stabilire se un'organizzazione internazionale controlla uno Stato o una parte consistente del suo territorio e se fornisce protezione come enunciato al paragrafo 2, gli Stati membri tengono conto degli eventuali orientamenti impartiti nei pertinenti atti del Consiglio.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Protezione all'interno del paese d'origine", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nell'ambito dell'esame della domanda di protezione internazionale, gli Stati membri possono stabilire che il richiedente non necessita di protezione internazionale se in una parte del territorio del paese d'origine egli non abbia fondati motivi di temere di essere perseguitato o non corra rischi effettivi di subire danni gravi e se è ragionevole attendere dal richiedente che si stabilisca in quella parte del paese.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel valutare se una parte del territorio del paese d'origine è conforme al paragrafo 1, gli Stati membri tengono conto delle condizioni generali vigenti in tale parte del paese nonché delle circostanze personali del richiedente all'epoca della decisione sulla domanda.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il paragrafo 1 si può applicare nonostante ostacoli tecnici al ritorno al paese d'origine.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Atti di persecuzione", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli atti di persecuzione ai sensi dell'articolo 1A della convenzione di Ginevra devono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">essere sufficientemente gravi, per loro natura o frequenza, da rappresentare una violazione grave dei diritti umani fondamentali, in particolare dei diritti per cui qualsiasi deroga è esclusa a norma dell'articolo 15, paragrafo 2, della convenzione europea di salvaguardia dei diritti dell'uomo e delle libertà fondamentali; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">costituire la somma di diverse misure, tra cui violazioni dei diritti umani, il cui impatto sia sufficientemente grave da esercitare sulla persona un effetto analogo a quello di cui alla lettera a).</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli atti di persecuzione che rientrano nella definizione di cui al paragrafo 1 possono, tra l'altro, assumere la forma di:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">atti di violenza fisica o psichica, compresa la violenza sessuale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedimenti legislativi, amministrativi, di polizia e/o giudiziari, discriminatori per loro stessa natura o attuati in modo discriminatorio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">azioni giudiziarie o sanzioni penali sproporzionate o discriminatorie;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rifiuto di accesso ai mezzi di ricorso giuridici e conseguente sanzione sproporzionata o discriminatoria;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">azioni giudiziarie o sanzioni penali in conseguenza al rifiuto di prestare servizio militare in un conflitto, quando questo comporterebbe la commissione di crimini, reati o atti che rientrano nelle clausole di esclusione di cui all'articolo 12, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">atti specificamente diretti contro un sesso o contro l'infanzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In conformità dell'articolo 2, lettera c), i motivi di cui all'articolo 10 devono essere collegati agli atti di persecuzione quali definiti al paragrafo 1.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Motivi di persecuzione", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nel valutare i motivi di persecuzione, gli Stati membri tengono conto dei seguenti elementi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il termine «razza» si riferisce, in particolare, a considerazioni inerenti al colore della pelle, alla discendenza o all'appartenenza ad un determinato gruppo etnico;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il termine «religione» include, in particolare, le convinzioni teiste, non teiste e ateiste, la partecipazione a, o l'astensione da, riti di culto celebrati in privato o in pubblico, sia singolarmente sia in comunità, altri atti religiosi o professioni di fede, nonché le forme di comportamento personale o sociale fondate su un credo religioso o da esso prescritte;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il termine «nazionalità» non si riferisce esclusivamente alla cittadinanza, o all'assenza di cittadinanza, ma designa, in particolare, l'appartenenza ad un gruppo caratterizzato da un'identità culturale, etnica o linguistica, comuni origini geografiche o politiche o la sua affinità con la popolazione di un altro Stato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">si considera che un gruppo costituisce un particolare gruppo sociale in particolare quando:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i membri di tale gruppo condividono una caratteristica innata o una storia comune che non può essere mutata oppure condividono una caratteristica o una fede che è così fondamentale per l'identità o la coscienza che una persona non dovrebbe essere costretta a rinunciarvi, e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">—</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tale gruppo possiede un'identità distinta nel paese di cui trattasi, perché vi è percepito come diverso dalla società circostante.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">In funzione delle circostanze nel paese d'origine, un particolare gruppo sociale può includere un gruppo fondato sulla caratteristica comune dell'orientamento sessuale. L'interpretazione dell'espressione «orientamento sessuale» non può includere atti classificati come penali dal diritto interno degli Stati membri; possono valere considerazioni di genere, sebbene non costituiscano di per sé stesse una presunzione di applicabilità del presente articolo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il termine «opinione politica» si riferisce, in particolare, alla professione di un'opinione, un pensiero o una convinzione su una questione inerente ai potenziali persecutori di cui all'articolo 6 e alle loro politiche o metodi, indipendentemente dal fatto che il richiedente abbia tradotto tale opinione, pensiero o convinzione in atti concreti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nell'esaminare se un richiedente abbia un timore fondato di essere perseguitato è irrilevante che il richiedente possegga effettivamente le caratteristiche razziali, religiose, nazionali, sociali o politiche che provocano gli atti di persecuzione, purché una siffatta caratteristica gli venga attribuita dall'autore delle persecuzioni.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Cessazione", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Un cittadino di un paese terzo o un apolide cessa di essere un rifugiato qualora:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">si sia volontariamente avvalso di nuovo della protezione del paese di cui ha la cittadinanza; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">avendo perso la cittadinanza, l'abbia volontariamente riacquistata; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">abbia acquistato una nuova cittadinanza e goda della protezione del paese di cui ha acquistato la cittadinanza; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">si sia volontariamente ristabilito nel paese che ha lasciato o in cui non ha fatto ritorno per timore di essere perseguitato; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">non possa più rinunciare alla protezione del paese di cui ha la cittadinanza, perché sono venute meno le circostanze che hanno determinato il riconoscimento dello status di rifugiato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se trattasi di un apolide, sia in grado di tornare nel paese nel quale aveva la dimora abituale, perché sono venute meno le circostanze che hanno determinato il riconoscimento dello status di rifugiato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ai fini dell'applicazione delle lettere e) e f) del paragrafo 1, gli Stati membri esaminano se il cambiamento delle circostanze ha un significato e una natura non temporanea tali da eliminare il fondato timore di persecuzioni.</p>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Esclusione", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Un cittadino di un paese terzo o un apolide è escluso dallo status di rifugiato se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rientra nel campo d'applicazione dell'articolo 1D della convenzione di Ginevra, relativo alla protezione o assistenza di un organo o di un'agenzia delle Nazioni unite diversi dall'Alto Commissario delle Nazioni unite per i rifugiati. Quando siffatta protezione o assistenza cessi per qualsiasi motivo, senza che la posizione di tali persone sia stata definitivamente stabilita in conformità delle pertinenti risoluzioni adottate dall'assemblea generale delle Nazioni unite, queste persone sono ipso facto ammesse ai benefici della presente direttiva;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le autorità competenti del paese nel quale ha stabilito la sua residenza gli riconoscono i diritti e gli obblighi connessi al possesso della cittadinanza del paese stesso o diritti e obblighi equivalenti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Un cittadino di un paese terzo o un apolide è escluso dallo status di rifugiato ove sussistano fondati motivi per ritenere:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che abbia commesso un crimine contro la pace, un crimine di guerra o un crimine contro l'umanità quali definiti dagli strumenti internazionali relativi a tali crimini;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che abbia commesso al di fuori del paese di accoglienza un reato grave di diritto comune prima di essere ammesso come rifugiato, ossia prima del momento in cui gli è rilasciato un permesso di soggiorno basato sul riconoscimento dello status di rifugiato, abbia commesso atti particolarmente crudeli, anche se perpetrati con un dichiarato obiettivo politico, che possono essere classificati quali reati gravi di diritto comune;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che si sia reso colpevole di atti contrari alle finalità e ai principi delle Nazioni unite quali stabiliti nel preambolo e negli articoli 1 e 2 della carta delle Nazioni unite.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il paragrafo 2 si applica alle persone che istigano o altrimenti concorrono alla commissione dei crimini, reati o atti in esso menzionati.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Riconoscimento dello status di rifugiato", "anchor": "art_13", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri riconoscono lo status di rifugiato al cittadino di un paese terzo o all'apolide ammissibile quale rifugiato in conformità dei capi II e III.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Revoca, cessazione o rifiuto del rinnovo dello status", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per quanto riguarda le domande di protezione internazionale presentate successivamente all'entrata in vigore della presente direttiva gli Stati membri revocano, cessano o rifiutano di rinnovare lo status di rifugiato riconosciuto a un cittadino di un paese terzo o a un apolide da un organismo statale, amministrativo, giudiziario o quasi giudiziario se questi ha cessato di essere un rifugiato ai sensi dell'articolo 11.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatto salvo l'obbligo del rifugiato, ai sensi dell'articolo 4, paragrafo 1, di rivelare tutti i fatti pertinenti e di produrre tutta la pertinente documentazione in suo possesso, lo Stato membro che ha riconosciuto lo status di rifugiato dimostra su base individuale che l'interessato ha cessato di essere o non è mai stato un rifugiato ai sensi del paragrafo 1 del presente articolo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri revocano, cessano o rifiutano di rinnovare lo status di rifugiato di un cittadino di un paese terzo o di un apolide qualora, successivamente al riconoscimento dello status di rifugiato, lo Stato membro interessato abbia stabilito che:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la persona in questione avrebbe dovuto essere esclusa o è esclusa dallo status di rifugiato ai sensi dell'articolo 12;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il fatto di aver presentato i fatti in modo erroneo o di averli omessi, compreso il ricorso a documenti falsi, ha costituito un fattore determinante per l'ottenimento dello status di rifugiato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri hanno la facoltà di revocare, di cessare o di rifiutare di rinnovare lo status riconosciuto a un rifugiato da un organismo statale, amministrativo, giudiziario o quasi giudiziario quando:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">vi sono fondati motivi per ritenere che la persona in questione costituisce un pericolo per la sicurezza dello Stato membro in cui si trova;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la persona in questione, essendo stata condannata con sentenza passata in giudicato per un reato di particolare gravità, costituisce un pericolo per la comunità di tale Stato membro.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Nelle situazioni previste al paragrafo 4, gli Stati membri possono decidere di non riconoscere lo status ad un rifugiato quando la decisione non è ancora stata presa.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le persone cui si applicano i paragrafi 4 o 5 godono dei diritti analoghi conferiti dagli articoli 3, 4, 16, 22, 31 e 32 e 33 della convenzione di Ginevra, o di diritti analoghi, purché siano presenti nello Stato membro.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Danno grave", "anchor": "art_15", "frags": [[null, "<p class=\"oj-normal\">Sono considerati danni gravi:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la condanna a morte o all'esecuzione; o</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la tortura o altra forma di pena o trattamento inumano o degradante ai danni del richiedente nel suo paese di origine; o</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la minaccia grave e individuale alla vita o alla persona di un civile derivante dalla violenza indiscriminata in situazioni di conflitto armato interno o internazionale.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "16": {"label": "Articolo 16", "heading": "Cessazione", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Un cittadino di un paese terzo o un apolide cessa di essere ammissibile a beneficiare della protezione sussidiaria quando le circostanze che hanno indotto alla concessione dello status di protezione sussidiaria sono venute meno o mutate in una misura tale che la protezione non è più necessaria.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nell'applicare il paragrafo 1 gli Stati membri considerano se le mutate circostanze siano di natura così significativa e non temporanea che la persona ammissibile a beneficiare della protezione sussidiaria non sia più esposta a un rischio effettivo di danno grave.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Esclusione", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Un cittadino di un paese terzo o un apolide è escluso dalla qualifica di persona ammissibile a beneficiare della protezione sussidiaria ove sussistano fondati motivi per ritenere:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che egli abbia commesso un crimine contro la pace, un crimine di guerra o un crimine contro l'umanità quali definiti dagli strumenti internazionali relativi a tali crimini;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che abbia commesso un reato grave;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che si sia reso colpevole di atti contrari alle finalità e ai principi delle Nazioni unite quali stabiliti nel preambolo e negli articoli 1 e 2 della carta delle Nazioni unite;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che rappresenti un pericolo per la comunità o la sicurezza dello Stato in cui si trova.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il paragrafo 1 si applica alle persone che istigano o altrimenti concorrono alla commissione dei crimini, reati o atti in esso menzionati.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri possono escludere un cittadino di un paese terzo o un apolide dalla qualifica di persona ammissibile a beneficiare della protezione sussidiaria se questi, prima di essere ammesso nello Stato membro, ha commesso uno o più reati non contemplati al paragrafo 1, che sarebbero punibili con la reclusione se fossero stati perpetrati nello Stato membro interessato e se ha lasciato il paese d'origine soltanto al fine di evitare le sanzioni risultanti da tali reati.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Riconoscimento dello status di protezione sussidiaria", "anchor": "art_18", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri riconoscono lo status di protezione sussidiaria a un cittadino di un paese terzo o a un apolide ammissibile a beneficiare della protezione sussidiaria in conformità dei capi II e V.</p>"]]}, "19": {"label": "Articolo 19", "heading": "Revoca, cessazione o rifiuto del rinnovo dello status di protezione sussidiaria", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per quanto riguarda le domande di protezione internazionale presentate successivamente all'entrata in vigore della presente direttiva gli Stati membri revocano, cessano o rifiutano di rinnovare lo status di protezione sussidiaria riconosciuta a un cittadino di un paese terzo o a un apolide da un organismo statale, amministrativo, giudiziario o quasi giudiziario se questi ha cessato di essere una persona ammissibile alla protezione sussidiaria in conformità dell'articolo 16.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri hanno la facoltà di revocare, di cessare o di rifiutare di rinnovare lo status di protezione sussidiaria riconosciuto a un cittadino di un paese terzo o a un apolide da un organismo statale, amministrativo, giudiziario o quasi giudiziario se questi, dopo aver ottenuto lo status di protezione sussidiaria, avrebbe dovuto essere escluso dall'ammissibilità a tale status in conformità dell'articolo 17, paragrafo 3.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri revocano, cessano o rifiutano di rinnovare lo status di protezione sussidiaria di un cittadino di un paese terzo o di un apolide se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">questi, successivamente al riconoscimento dello status di protezione sussidiaria, avrebbe dovuto essere escluso o è escluso dalla qualifica di persona ammissibile a beneficiare della protezione sussidiaria ai sensi dell'articolo 17, paragrafi 1 e 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il fatto di aver presentato i fatti in modo erroneo o di averli omessi, compreso il ricorso a documenti falsi, ha costituito un fattore determinante per l'ottenimento dello status di protezione sussidiaria.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Fatto salvo l'obbligo del cittadino di un paese terzo o dell'apolide, ai sensi dell'articolo 4, paragrafo 1, di rivelare tutti i fatti pertinenti e di produrre tutta la pertinente documentazione in suo possesso, lo Stato membro che ha riconosciuto lo status di protezione sussidiaria dimostra su base individuale che l'interessato ha cessato di essere o non è ammissibile a beneficiare della protezione sussidiaria ai sensi dei paragrafi da 1 a 3 del presente articolo.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Disposizioni generali", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le disposizioni del presente capo non pregiudicano i diritti sanciti dalla convenzione di Ginevra.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le disposizioni del presente capo si applicano sia ai rifugiati sia alle persone ammissibili a beneficiare della protezione sussidiaria, ove non diversamente indicato.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nell'attuare il presente capo, gli Stati membri tengono conto della specifica situazione di persone vulnerabili, quali i minori, i minori non accompagnati, i disabili, gli anziani, le donne in stato di gravidanza, i genitori singoli con figli minori, le persone che hanno subito torture, stupri o altre forme gravi di violenza psicologia, fisica o sessuale.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il paragrafo 3 si applica soltanto alle persone per cui si riscontrano esigenze particolari mediante la valutazione della loro situazione individuale.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il prevalente interesse del minore è la principale considerazione degli Stati membri quando attuano le disposizioni del presente capo che coinvolgono i minori.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Entro i limiti stabiliti dalla convenzione di Ginevra, gli Stati membri hanno la facoltà di ridurre i benefici del presente capo, riconosciuti a un rifugiato, il cui status di rifugiato sia stato ottenuto per attività svolte al fine esclusivo o principale di creare le condizioni necessarie al riconoscimento di tale status.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Entro i limiti derivanti dagli obblighi internazionali degli Stati membri, gli Stati membri hanno la facoltà di ridurre i benefici del presente capo, riconosciuti ad una persona ammissibile a beneficiare della protezione sussidiaria, il cui status di protezione sussidiaria sia stato ottenuto per attività svolte al fine esclusivo o principale di creare le condizioni necessarie al riconoscimento come persona ammissibile alla protezione sussidiaria.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Protezione dal respingimento", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri rispettano il principio di «non refoulement» in conformità dei propri obblighi internazionali.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora non sia vietato dagli obblighi internazionali previsti dal paragrafo 1, gli Stati membri possono respingere un rifugiato, formalmente riconosciuto o meno, quando:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">vi siano ragionevoli motivi per considerare che detta persona rappresenti un pericolo per la sicurezza dello Stato membro nel quale si trova; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che, essendo stata condannata con sentenza passata in giudicato per un reato di particolare gravità, detta persona costituisca un pericolo per la comunità di tale Stato membro.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri hanno la facoltà di revocare, di cessare o di rifiutare il rinnovo o il rilascio di un permesso di soggiorno di un (o a un) rifugiato al quale si applichi il paragrafo 2.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Informazioni", "anchor": "art_22", "frags": [[null, "<p class=\"oj-normal\">Quanto prima possibile dopo aver riconosciuto loro lo status, gli Stati membri forniscono alle persone che considerano bisognose di protezione internazionale, in una lingua che queste siano in grado di comprendere, l'accesso a informazioni sui diritti e gli obblighi previsti dallo status di protezione loro applicabile.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Mantenimento dell'unità del nucleo familiare", "anchor": "art_23", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono a che possa essere preservata l'unità del nucleo familiare.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono a che i familiari del beneficiario dello status di rifugiato o della protezione sussidiaria, che individualmente non hanno diritto a tale status o protezione, siano ammessi ai benefici di cui agli articoli da 24 a 34, in conformità delle procedure nazionali e nella misura in cui ciò sia compatibile con lo status giuridico personale del familiare.</p>\n<p class=\"oj-normal\">Gli Stati membri possono definire le condizioni applicabili ai benefici relativi ai familiari dei beneficiari della protezione sussidiaria.</p>\n<p class=\"oj-normal\">In tali casi gli Stati membri assicurano che i benefici offerti garantiscano un adeguato tenore di vita.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I paragrafi 1 e 2 non si applicano quando il familiare è o sarebbe escluso dallo status di rifugiato o dalla protezione sussidiaria in base ai capi III e V.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nonostante i paragrafi 1 e 2, gli Stati membri possono rifiutare, ridurre o revocare i benefici ivi menzionati, per motivi di sicurezza nazionale o di ordine pubblico.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri possono decidere che il presente articolo si applica anche agli altri congiunti che vivevano nel nucleo familiare al momento della partenza dal paese d'origine e che in quel momento erano completamente o principalmente a carico del beneficiario dello status di rifugiato o della protezione sussidiaria.</p>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Permesso di soggiorno", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri rilasciano ai beneficiari dello status di rifugiato, il più presto possibile dopo aver riconosciuto loro lo status, un permesso di soggiorno valido per un periodo di almeno tre anni rinnovabile, purché non vi ostino imperiosi motivi di sicurezza nazionale o di ordine pubblico e fatto salvo l'articolo 21, paragrafo 3.</p>\n<p class=\"oj-normal\">Fatto salvo l'articolo 23, paragrafo 1, il permesso di soggiorno da rilasciare ai familiari dei beneficiari dello status di rifugiato può essere valido per un periodo inferiore a tre anni e rinnovabile.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri rilasciano ai beneficiari della protezione sussidiaria, il più presto possibile dopo aver riconosciuto loro lo status, un permesso di soggiorno valido per un periodo non inferiore ad un anno rinnovabile, purché non vi ostino imperiosi motivi di sicurezza nazionale o di ordine pubblico.</p>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Documenti di viaggio", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri rilasciano ai beneficiari dello status di rifugiato documenti di viaggio nella forma prevista dall'allegato della convenzione di Ginevra, allo scopo di permettere loro di viaggiare al di fuori del loro territorio, purché non vi ostino imperiosi motivi di sicurezza nazionale o di ordine pubblico.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri rilasciano ai beneficiari della protezione sussidiaria che si trovino nell'impossibilità di ottenere un passaporto nazionale, documenti che consentono loro di viaggiare, almeno quando sussistano gravi ragioni umanitarie che rendano necessaria la loro presenza in un altro Stato, purché non vi ostino imperiosi motivi di sicurezza nazionale o di ordine pubblico.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Accesso all'occupazione", "anchor": "art_26", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri autorizzano i beneficiari dello status di rifugiato ad esercitare un'attività dipendente o autonoma nel rispetto della normativa generalmente applicabile alle professioni e agli impieghi nella pubblica amministrazione, non appena sia stato loro riconosciuto lo status di rifugiato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri provvedono a che siano offerte ai beneficiari dello status di rifugiato opportunità di formazione occupazionale per adulti, formazione professionale e tirocinio sul luogo di lavoro secondo modalità equivalenti a quelle previste per i loro cittadini.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri autorizzano i beneficiari dello status di protezione sussidiaria ad esercitare un'attività dipendente o autonoma nel rispetto della normativa generalmente applicabile alle professioni e agli impieghi nella pubblica amministrazione, non appena sia stato loro riconosciuto lo status di protezione sussidiaria. Può essere tenuta in considerazione la situazione esistente sul mercato del lavoro degli Stati membri, eventualmente anche per stabilire un ordine di precedenza per l'accesso all'occupazione per un periodo di tempo limitato da determinare conformemente alla normativa nazionale. Gli Stati membri provvedono a che i beneficiari dello status di protezione sussidiaria accedano al posto per il quale hanno ricevuto un'offerta, in conformità delle norme nazionali in materia di ordine di precedenza sul mercato del lavoro.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri provvedono a che ai beneficiari dello status di protezione sussidiaria siano offerte opportunità di formazione occupazionale per adulti, formazione professionale e tirocinio sul luogo di lavoro secondo modalità che saranno decise dagli Stati membri stessi.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Si applica la normativa vigente negli Stati membri in materia di retribuzione, di accesso ai regimi di sicurezza sociale connessa all'attività di lavoro dipendente o autonomo, nonché di ogni altra condizione di lavoro.</p>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Accesso all'istruzione", "anchor": "art_27", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri offrono il pieno accesso al sistema scolastico, secondo le stesse modalità previste per i loro cittadini, a tutti i minori beneficiari dello status di rifugiato o della protezione sussidiaria.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri consentono agli adulti beneficiari dello status di rifugiato o della protezione sussidiaria di accedere al sistema di istruzione generale e di aggiornamento e perfezionamento professionale secondo le stessa modalità previste per i cittadini di paesi terzi in soggiorno regolare.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri garantiscono la parità di trattamento tra i beneficiari dello status di rifugiato o della protezione sussidiaria ed i loro cittadini nel quadro delle vigenti procedure di riconoscimento di diplomi, certificati ed altri titoli stranieri.</p>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Assistenza sociale", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché i beneficiari dello status di rifugiato o di protezione sussidiaria ricevano, nello Stato membro che ha concesso tali status, adeguata assistenza sociale, alla stregua dei cittadini Stato membro in questione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In via d'eccezione alla regola generale di cui al paragrafo 1, gli Stati membri possono limitare l'assistenza sociale per i beneficiari della protezione sussidiaria alle prestazioni essenziali, che in tal caso sono offerte allo stesso livello e alle stesse condizioni di ammissibilità previste per i cittadini dello Stato membro in questione.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Assistenza sanitaria", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono a che i beneficiari dello status di rifugiato o di protezione sussidiaria abbiano accesso all'assistenza sanitaria secondo le stesse modalità previste per i cittadini dello Stato membro che ha riconosciuto loro tali status.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   In via d'eccezione alla regola generale di cui al paragrafo 1, gli Stati membri possono limitare l'assistenza sanitaria per i beneficiari della protezione sussidiaria alle prestazioni essenziali, che in tal caso sono offerte allo stesso livello e alle stesse condizioni di ammissibilità previste per i cittadini dello Stato membro in questione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri forniscono adeguata assistenza sanitaria, secondo le stesse modalità previste per i cittadini dello Stato membro che ha concesso tali status, ai beneficiari dello status di rifugiato o di protezione sussidiaria che presentano particolari esigenze, quali le donne in stato di gravidanza, i disabili, le vittime di torture, stupri o altre gravi forme di violenza psicologica, fisica o sessuale, o i minori che abbiano subito qualsiasi forma di abuso, negligenza, sfruttamento, tortura, trattamento crudele, disumano o degradante o che abbiano sofferto gli effetti di un conflitto armato.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Minori non accompagnati", "anchor": "art_30", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri adottano quanto prima dopo la concessione dello status di rifugiato o di protezione sussidiaria, misure atte ad assicurare la necessaria rappresentanza dei minori non accompagnati, da parte di un tutore legale oppure, ove necessario, la rappresentanza da parte di un organismo incaricato della cura e del benessere dei minori, oppure qualsiasi altra forma adeguata di rappresentanza, inclusa quella basata sulla legislazione o su un provvedimento giudiziario.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel dare attuazione alla presente direttiva, gli Stati membri provvedono affinché le esigenze del minore siano debitamente soddisfatte dal tutore o rappresentante designato. Le autorità competenti procedono a valutazioni periodiche.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri provvedono affinché i minori non accompagnati siano alloggiati:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presso familiari adulti; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">presso una famiglia affidataria; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in centri specializzati nell'ospitare i minori; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">secondo altre modalità che offrano un alloggio idoneo per i minori.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">In questo contento si tiene conto del parere del minore conformemente all'età e al grado di maturità dello stesso</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Per quanto possibile i fratelli sono alloggiati insieme, tenendo conto del prevalente interesse del minore in questione e, in particolare, della sua età e del grado di maturità. I cambi di residenza di minori non accompagnati sono limitati al minimo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri, a tutela del prevalente interesse del minore non accompagnato, si adoperano per rintracciare quanto prima i suoi familiari. Nei casi in cui sussistano rischi per la vita o l'integrità del minore o dei suoi parenti stretti, in particolare se questi sono rimasti nel paese di origine, la raccolta, il trattamento e la diffusione delle informazioni relative a queste persone sono effettuate in via confidenziale.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le persone che si occupano di minori non accompagnati devono aver ricevuto o ricevono una specifica formazione in merito alle particolari esigenze degli stessi.</p>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Accesso all'alloggio", "anchor": "art_31", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri provvedono a che i beneficiari dello status di rifugiato o della protezione sussidiaria abbiano accesso ad un alloggio secondo modalità equivalenti a quelle previste per altri cittadini di paesi terzi in soggiorno regolare nei loro territori.</p>"]]}, "32": {"label": "Articolo 32", "heading": "Libera circolazione nel territorio dello Stato membro", "anchor": "art_32", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri concedono ai beneficiari dello status di rifugiato o della protezione sussidiaria la libertà di circolazione all'interno del territorio nazionale, secondo le stesse modalità e restrizioni previste per altri cittadini di paesi terzi in soggiorno regolare nei loro territori.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Accesso agli strumenti di integrazione", "anchor": "art_33", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al fine di facilitare l'integrazione dei rifugiati nella società, gli Stati membri stabiliscono i programmi d'integrazione che considerano adeguati o creano i presupposti che garantiscono l'accesso a tali programmi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Laddove lo ritengano opportuno, gli Stati membri consentono ai beneficiari dello status di protezione sussidiaria di accedere ai programmi d'integrazione.</p>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Rimpatrio", "anchor": "art_34", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri possono fornire assistenza ai beneficiari dello status di rifugiato o di protezione sussidiaria che desiderano rimpatriare.</p>"]]}, "35": {"label": "Articolo 35", "heading": "Cooperazione", "anchor": "art_35", "frags": [[null, "<p class=\"oj-normal\">Ciascuno Stato membro designa un punto nazionale di contatto, trasmettendone l'indirizzo alla Commissione che a sua volta lo comunica a tutti gli altri Stati membri.</p>"], [null, "<p class=\"oj-normal\">Gli Stati membri, in collegamento con la Commissione, adottano ogni misura idonea ad instaurare una cooperazione diretta e lo scambio di informazioni tra le autorità competenti.</p>"]]}, "36": {"label": "Articolo 36", "heading": "Personale", "anchor": "art_36", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri adottano le misure necessarie affinché tutte le autorità competenti e le altre organizzazioni che danno attuazione alla presente direttiva abbiano ricevuto la necessaria formazione di base e siano soggette, conformemente a quanto stabilito dal diritto nazionale, all'obbligo di riservatezza relativamente alle informazioni di cui dovessero venire a conoscenza durante l'attività da loro svolta.</p>"]]}, "37": {"label": "Articolo 37", "heading": "Relazioni", "anchor": "art_37", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 10 aprile 2008, la Commissione presenta al Parlamento europeo e al Consiglio una relazione sull'applicazione della presente direttiva negli Stati membri, proponendo all'occorrenza le necessarie modifiche. Dette proposte di modifica riguardano in via prioritaria agli articoli 15, 26 e 33. Gli Stati membri trasmettono alla Commissione ogni informazione utile ai fini di tale relazione entro il 10 ottobre 2007.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Successivamente, la Commissione riferisce al Parlamento europeo e al Consiglio almeno ogni cinque anni sull'applicazione della presente direttiva.</p>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Recepimento", "anchor": "art_38", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri mettono in vigore le disposizioni legislative, regolamentari ed amministrative necessarie per conformarsi alla presente direttiva entro il 10 ottobre 2006. Essi ne informano immediatamente la Commissione.</p>\n<p class=\"oj-normal\">Quando gli Stati membri adottano tali disposizioni, queste contengono un riferimento alla presente direttiva o sono corredate di un siffatto riferimento all'atto della pubblicazione ufficiale. Gli Stati membri determinano le modalità di tali riferimenti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri trasmettono alla Commissione il testo delle disposizioni nazionali di legge che adottano nel settore trattato dalla presente direttiva.</p>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Entrata in vigore", "anchor": "art_39", "frags": [[null, "<p class=\"oj-normal\">La presente direttiva entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span>.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Destinatari", "anchor": "art_40", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri sono destinatari della presente direttiva conformemente al trattato che istituisce la Comunità europea.</p>"]]}}, "recitals": {}};